import { useState, useEffect, useCallback } from 'react';
import { Alarm, TimeState } from '../types';

export const useAlarms = (currentTime: TimeState) => {
  const [alarms, setAlarms] = useState<Alarm[]>(() => {
    const saved = localStorage.getItem('chrono_alarms');
    return saved ? JSON.parse(saved) : [];
  });

  const [triggeredAlarm, setTriggeredAlarm] = useState<Alarm | null>(null);

  useEffect(() => {
    localStorage.setItem('chrono_alarms', JSON.stringify(alarms));
  }, [alarms]);

  // Check for alarm triggers
  useEffect(() => {
    const nowStr = `${currentTime.hours}:${currentTime.minutes}`;
    // We only want to trigger if seconds are 00 to avoid multiple triggers in one minute, 
    // OR we track "last triggered" state. 
    // Simple approach: trigger if seconds is "00" and alarm matches.

    if (currentTime.seconds === "00") {
      const matchingAlarm = alarms.find(a => {
        // Convert alarm 24h to current time format or vice versa.
        // Simplified: Let's assume user inputs 24h, we convert TimeState to 24h for comparison.

        // Construct 24h string from TimeState
        let hours24 = parseInt(currentTime.hours);
        if (currentTime.ampm === 'PM' && hours24 !== 12) hours24 += 12;
        if (currentTime.ampm === 'AM' && hours24 === 12) hours24 = 0;

        const current24h = `${hours24.toString().padStart(2, '0')}:${currentTime.minutes}`;
        return a.time === current24h && a.isActive;
      });

      if (matchingAlarm) {
        setTriggeredAlarm(matchingAlarm);
        playAlarmSound();
      }
    }
  }, [currentTime.hours, currentTime.minutes, currentTime.seconds, currentTime.ampm, alarms]);

  const addAlarm = (time: string, label: string) => {
    const newAlarm: Alarm = {
      id: Date.now().toString(),
      time,
      label: label || 'Alarm',
      isActive: true
    };
    setAlarms(prev => [...prev, newAlarm]);
  };

  const removeAlarm = (id: string) => {
    setAlarms(prev => prev.filter(a => a.id !== id));
  };

  const toggleAlarm = (id: string) => {
    setAlarms(prev => prev.map(a => a.id === id ? { ...a, isActive: !a.isActive } : a));
  };

  const dismissAlarm = () => {
    setTriggeredAlarm(null);
  };

  const playAlarmSound = () => {
    // Simple oscillator beep
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.type = 'sine';
    osc.frequency.setValueAtTime(440, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);

    osc.start();
    osc.stop(ctx.currentTime + 0.5);
  };

  return {
    alarms,
    addAlarm,
    removeAlarm,
    toggleAlarm,
    triggeredAlarm,
    dismissAlarm
  };
};

import React, { useState } from 'react';
import { Alarm } from '../types';

interface AlarmManagerProps {
  alarms: Alarm[];
  onAdd: (time: string, label: string) => void;
  onRemove: (id: string) => void;
  onToggle: (id: string) => void;
  isDarkMode: boolean;
}

export const AlarmManager: React.FC<AlarmManagerProps> = ({ alarms, onAdd, onRemove, onToggle, isDarkMode }) => {
  const [newTime, setNewTime] = useState('');
  const [newLabel, setNewLabel] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTime) {
      onAdd(newTime, newLabel);
      setNewTime('');
      setNewLabel('');
    }
  };

  const inputClass = `w-full bg-transparent border-b ${isDarkMode ? 'border-white/20 text-white placeholder-slate-500' : 'border-slate-300 text-slate-800 placeholder-slate-400'} focus:outline-none focus:border-blue-500 py-2 text-sm transition-colors`;

  return (
    <div className="space-y-4">
      <h2 className={`text-xs font-semibold uppercase tracking-wider ${isDarkMode ? 'text-slate-500' : 'text-slate-500'}`}>Alarms</h2>

      <form onSubmit={handleSubmit} className={`p-3 rounded-xl border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-slate-100 border-slate-200'} space-y-3`}>
        <div className="flex space-x-2">
          <input 
            type="time" 
            value={newTime}
            onChange={(e) => setNewTime(e.target.value)}
            required
            className={inputClass}
          />
          <input 
            type="text" 
            placeholder="Label"
            value={newLabel}
            onChange={(e) => setNewLabel(e.target.value)}
            className={inputClass}
          />
        </div>
        <button 
          type="submit"
          className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold uppercase tracking-wider rounded-lg transition-colors"
        >
          Add Alarm
        </button>
      </form>

      <div className="space-y-2 max-h-48 overflow-y-auto pr-1 custom-scrollbar">
        {alarms.length === 0 && (
          <p className="text-xs text-center opacity-50 italic py-2">No alarms set</p>
        )}
        {alarms.map(alarm => (
          <div 
            key={alarm.id} 
            className={`flex items-center justify-between p-3 rounded-lg border transition-all ${
              isDarkMode 
                ? 'bg-white/5 border-white/5 hover:bg-white/10' 
                : 'bg-white border-slate-200 hover:bg-slate-50 shadow-sm'
            }`}
          >
            <div className="flex flex-col">
              <span className={`text-lg font-mono leading-none ${!alarm.isActive && 'opacity-50'} ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>
                {alarm.time}
              </span>
              <span className={`text-[10px] ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>{alarm.label}</span>
            </div>

            <div className="flex items-center space-x-3">
              <button 
                onClick={() => onToggle(alarm.id)}
                className={`w-8 h-4 rounded-full relative transition-colors ${alarm.isActive ? 'bg-blue-500' : (isDarkMode ? 'bg-slate-700' : 'bg-slate-300')}`}
              >
                <div className={`absolute top-0.5 w-3 h-3 rounded-full bg-white transition-transform ${alarm.isActive ? 'left-4.5 translate-x-1' : 'left-0.5'}`}></div>
              </button>
              <button 
                onClick={() => onRemove(alarm.id)}
                className="text-slate-500 hover:text-red-500 transition-colors"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          </div>
        ))}
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #475569; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
      `}</style>
    </div>
  );
};

