import React, { useState, useEffect } from 'react';
import { useTime } from './hooks/useTime';
import { useAlarms } from './hooks/useAlarms';
import { THEMES } from './constants';
import { QuoteData } from './types';
import { AppleClock, MicrosoftClock, JapanClock, IndiaClock, ChinaClock } from './components/ClockThemes';
import { AlarmManager } from './components/AlarmManager';
import { getCulturalQuote } from './services/geminiService';

const App: React.FC = () => {
  const time = useTime();
  const [currentThemeId, setCurrentThemeId] = useState<string>('apple');
  const [isWidgetMode, setIsWidgetMode] = useState<boolean>(false);
  const [themeMode, setThemeMode] = useState<'light' | 'dark'>('dark');
  const [quote, setQuote] = useState<QuoteData | null>(null);
  const [loadingQuote, setLoadingQuote] = useState<boolean>(false);

  const { alarms, addAlarm, removeAlarm, toggleAlarm, triggeredAlarm, dismissAlarm } = useAlarms(time);

  const currentTheme = THEMES.find(t => t.id === currentThemeId) || THEMES[0];
  const currentStyles = currentTheme.modes[themeMode];

  // Fetch a new quote when theme changes
  useEffect(() => {
    const fetchQuote = async () => {
      setLoadingQuote(true);
      const data = await getCulturalQuote(currentThemeId);
      setQuote(data);
      setLoadingQuote(false);
    };
    fetchQuote();
  }, [currentThemeId]);

  const toggleWidgetMode = () => {
    setIsWidgetMode(!isWidgetMode);
  };

  const renderClockFace = () => {
    const props = { time, mode: themeMode, themeStyles: currentStyles };
    switch (currentThemeId) {
      case 'apple': return <AppleClock {...props} />;
      case 'microsoft': return <MicrosoftClock {...props} />;
      case 'japan': return <JapanClock {...props} />;
      case 'india': return <IndiaClock {...props} />;
      case 'china': return <ChinaClock {...props} />;
      default: return <AppleClock {...props} />;
    }
  };

  return (
    <div className={`min-h-screen w-full flex items-center justify-center transition-all duration-700 ease-in-out bg-cover bg-center ${isWidgetMode ? 'p-0' : 'p-4 md:p-8'}`}
         style={{ 
           backgroundImage: isWidgetMode ? 'none' : `url('https://picsum.photos/1920/1080?blur=10')`,
           backgroundColor: isWidgetMode ? 'transparent' : undefined
         }}>

      {/* Background Overlay for Main App Mode */}
      {!isWidgetMode && <div className="absolute inset-0 bg-black/40 backdrop-blur-sm"></div>}

      {/* Alarm Overlay Modal */}
      {triggeredAlarm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md animate-in fade-in zoom-in duration-300">
           <div className={`p-8 rounded-2xl shadow-2xl flex flex-col items-center text-center max-w-sm w-full mx-4 border ${themeMode === 'dark' ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-200'}`}>
              <div className="w-16 h-16 rounded-full bg-red-500/20 flex items-center justify-center mb-4 animate-bounce">
                <svg className="w-8 h-8 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
              </div>
              <h2 className={`text-3xl font-bold mb-2 ${themeMode === 'dark' ? 'text-white' : 'text-slate-900'}`}>{time.hours}:{time.minutes}</h2>
              <p className={`text-lg mb-6 ${themeMode === 'dark' ? 'text-slate-300' : 'text-slate-600'}`}>{triggeredAlarm.label || "Alarm Triggered"}</p>
              <button 
                onClick={dismissAlarm}
                className="w-full py-3 bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl transition-colors shadow-lg shadow-red-500/30"
              >
                Dismiss
              </button>
           </div>
        </div>
      )}

      {/* Main Container */}
      <div 
        className={`
          relative flex flex-col items-center transition-all duration-500 ease-spring
          ${isWidgetMode ? 'w-full h-screen' : 'w-full max-w-6xl h-[700px] shadow-2xl rounded-3xl overflow-hidden grid grid-cols-1 lg:grid-cols-12'}
        `}
      >

        {/* Sidebar / Controls */}
        {!isWidgetMode && (
          <div className={`
             lg:col-span-4 p-6 flex flex-col justify-between overflow-y-auto border-r transition-colors duration-300
             ${themeMode === 'dark' ? 'bg-slate-900/90 text-white border-white/10' : 'bg-white/90 text-slate-800 border-slate-200'}
          `}>
            <div>
              <div className="flex items-center justify-between mb-2">
                 <h1 className="text-2xl font-bold tracking-tight">ChronoVerse</h1>
                 <button 
                   onClick={() => setThemeMode(prev => prev === 'light' ? 'dark' : 'light')}
                   className={`p-2 rounded-full transition-colors ${themeMode === 'dark' ? 'bg-white/10 hover:bg-white/20' : 'bg-slate-100 hover:bg-slate-200'}`}
                   title="Toggle Theme Mode"
                 >
                   {themeMode === 'dark' ? (
                     <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
                   ) : (
                     <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" /></svg>
                   )}
                 </button>
              </div>
              <p className={`text-sm mb-6 ${themeMode === 'dark' ? 'text-slate-400' : 'text-slate-500'}`}>Desktop Widget Engine</p>

              {/* Tabs or Sections */}
              <div className="space-y-6">

                {/* Style Selector */}
                <div className="space-y-2">
                  <h2 className={`text-xs font-semibold uppercase tracking-wider ${themeMode === 'dark' ? 'text-slate-500' : 'text-slate-500'}`}>Select Style</h2>
                  <div className="grid grid-cols-1 gap-2">
                    {THEMES.map(theme => (
                      <button
                        key={theme.id}
                        onClick={() => setCurrentThemeId(theme.id)}
                        className={`w-full text-left p-3 rounded-xl transition-all duration-200 flex items-center space-x-3 border
                          ${currentThemeId === theme.id 
                            ? (themeMode === 'dark' ? 'bg-slate-800 border-blue-500/50 shadow-blue-500/10' : 'bg-blue-50 border-blue-200 shadow-sm')
                            : (themeMode === 'dark' ? 'border-transparent hover:bg-white/5' : 'border-transparent hover:bg-slate-100')}
                        `}
                      >
                        <div className={`w-3 h-3 rounded-full ${theme.modes[themeMode].accentClass}`}></div>
                        <div>
                          <span className="block font-medium">{theme.name}</span>
                          <span className={`text-[10px] opacity-70 block ${themeMode === 'dark' ? 'text-slate-400' : 'text-slate-500'}`}>{theme.type}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                {/* Alarm Manager */}
                <AlarmManager 
                  alarms={alarms} 
                  onAdd={addAlarm} 
                  onRemove={removeAlarm} 
                  onToggle={toggleAlarm}
                  isDarkMode={themeMode === 'dark'}
                />

              </div>
            </div>

            <div className="mt-8 space-y-4">
              <div className={`rounded-xl p-4 border ${themeMode === 'dark' ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-200'}`}>
                 <h3 className="text-sm font-semibold text-blue-400 mb-1 flex items-center gap-2">
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                   AI Insight
                 </h3>
                 {loadingQuote ? (
                   <div className="h-12 w-full animate-pulse bg-current opacity-10 rounded"></div>
                 ) : (
                   <div className={`text-xs italic ${themeMode === 'dark' ? 'text-slate-300' : 'text-slate-600'}`}>
                     "{quote?.text}"
                     <div className="text-right mt-1 opacity-70 not-italic">- {quote?.author}</div>
                   </div>
                 )}
              </div>

              <button 
                onClick={toggleWidgetMode}
                className={`w-full py-3 rounded-xl font-medium transition-colors border flex items-center justify-center gap-2
                  ${themeMode === 'dark' ? 'bg-white/10 hover:bg-white/20 border-white/5' : 'bg-slate-800 text-white hover:bg-slate-700 border-transparent'}
                `}
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                </svg>
                Launch Widget Mode
              </button>
            </div>
          </div>
        )}

        {/* Clock Display Area */}
        <div className={`
            relative overflow-hidden transition-all duration-500
            ${isWidgetMode ? 'w-full h-full' : 'lg:col-span-8 bg-black/5'}
            ${currentStyles.containerClass}
            ${isWidgetMode && 'rounded-none border-0 shadow-none'}
        `}>

          {/* Controls Overlay in Widget Mode */}
          {isWidgetMode && (
            <div className="absolute top-4 right-4 z-50 group">
              <button 
                onClick={toggleWidgetMode}
                className="p-2 bg-black/20 hover:bg-red-500/80 backdrop-blur-md text-white rounded-full opacity-0 group-hover:opacity-100 transition-all duration-300"
                title="Exit Widget Mode"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
          )}

          {renderClockFace()}

          {/* AI Quote Overlay on Widget (Subtle) */}
          {isWidgetMode && quote && (
            <div className="absolute bottom-8 w-full text-center px-8 z-20 pointer-events-none">
              <p className={`text-sm opacity-60 mix-blend-overlay ${currentStyles.textClass} font-medium`}>
                {quote.text}
              </p>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

