import { useState, useEffect, useCallback } from 'react';
import { Alarm, TimeState } from '../types';

export const useAlarms = (currentTime: TimeState) => {
  const [alarms, setAlarms] = useState<Alarm[]>(() => {
    const saved = localStorage.getItem('chrono_alarms');
    return saved ? JSON.parse(saved) : [];
  });

  const [triggeredAlarm, setTriggeredAlarm] = useState<Alarm | null>(null);

  useEffect(() => {
    localStorage.setItem('chrono_alarms', JSON.stringify(alarms));
  }, [alarms]);

  // Check for alarm triggers
  useEffect(() => {
    const nowStr = `${currentTime.hours}:${currentTime.minutes}`;
    // We only want to trigger if seconds are 00 to avoid multiple triggers in one minute, 
    // OR we track "last triggered" state. 
    // Simple approach: trigger if seconds is "00" and alarm matches.

    // Fix: seconds is a number, so we compare with 0 instead of "00"
    if (currentTime.seconds === 0) {
      const matchingAlarm = alarms.find(a => {
        // Convert alarm 24h to current time format or vice versa.
        // Simplified: Let's assume user inputs 24h, we convert TimeState to 24h for comparison.

        // Construct 24h string from TimeState
        // Fix: hours is already a number (0-23) in TimeState, so we use it directly.
        // Removed parseInt (which caused a type error) and the redundant 12h->24h conversion logic.
        const hours24 = currentTime.hours;

        const current24h = `${hours24.toString().padStart(2, '0')}:${currentTime.minutes.toString().padStart(2, '0')}`;
        return a.time === current24h && a.isActive;
      });

      if (matchingAlarm) {
        setTriggeredAlarm(matchingAlarm);
        playAlarmSound();
      }
    }
  }, [currentTime.hours, currentTime.minutes, currentTime.seconds, currentTime.ampm, alarms]);

  const addAlarm = (time: string, label: string) => {
    const newAlarm: Alarm = {
      id: Date.now().toString(),
      time,
      label: label || 'Alarm',
      isActive: true
    };
    setAlarms(prev => [...prev, newAlarm]);
  };

  const removeAlarm = (id: string) => {
    setAlarms(prev => prev.filter(a => a.id !== id));
  };

  const toggleAlarm = (id: string) => {
    setAlarms(prev => prev.map(a => a.id === id ? { ...a, isActive: !a.isActive } : a));
  };

  const dismissAlarm = () => {
    setTriggeredAlarm(null);
  };

  const playAlarmSound = () => {
    // Simple oscillator beep
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.type = 'sine';
    osc.frequency.setValueAtTime(440, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);

    osc.start();
    osc.stop(ctx.currentTime + 0.5);
  };

  return {
    alarms,
    addAlarm,
    removeAlarm,
    toggleAlarm,
    triggeredAlarm,
    dismissAlarm
  };
};

