import React from 'react';
import { TimeState, ThemeModeData, ClockSettings } from '../types';

interface ClockFaceProps {
  time: TimeState;
  mode: 'light' | 'dark';
  themeStyles: ThemeModeData;
  settings: ClockSettings;
}

// Helper to format hours based on settings
const getDisplayHours = (hours: number, is24Hour: boolean): string => {
  if (is24Hour) return hours.toString().padStart(2, '0');
  const h = hours % 12 || 12;
  return h.toString().padStart(2, '0');
};

const pad = (num: number) => num.toString().padStart(2, '0');

// Helper for custom color styles
const useColorStyle = (customColor: string | null) => {
  return customColor ? { color: customColor } : {};
};

// --- 1. Swiss Analog Clock ---
export const SwissClock: React.FC<ClockFaceProps> = ({ time, mode, themeStyles, settings }) => {
  const secondDeg = (time.seconds / 60) * 360;
  const minuteDeg = (time.minutes / 60) * 360 + (time.seconds / 60) * 6;
  const hourDeg = ((time.hours % 12) / 12) * 360 + (time.minutes / 60) * 30;
  const colorStyle = useColorStyle(settings.customColor);

  return (
    <div className={`relative w-[90%] h-[90%] rounded-full ${themeStyles.containerClass}`}>
       <div className="absolute inset-0 rounded-full">
         {[...Array(12)].map((_, i) => (
           <div 
             key={i} 
             className={`absolute w-2 h-6 left-1/2 -ml-1 top-4 origin-center ${mode === 'dark' ? 'bg-gray-300' : 'bg-gray-800'}`}
             style={{ transform: `rotate(${i * 30}deg) translate(0, 10px)`, backgroundColor: settings.customColor || undefined }} 
           />
         ))}
         {[...Array(60)].map((_, i) => (
           <div 
             key={i} 
             className={`absolute w-0.5 h-2 left-1/2 -ml-px top-4 origin-center ${mode === 'dark' ? 'bg-gray-600' : 'bg-gray-400'}`}
             style={{ transform: `rotate(${i * 6}deg) translate(0, 10px)` }} 
           />
         ))}
       </div>

       {settings.showDate && (
         <div className={`absolute right-[20%] top-1/2 -translate-y-1/2 border px-2 py-0.5 rounded text-sm font-semibold tracking-wider ${mode === 'dark' ? 'border-gray-700 bg-gray-800 text-gray-200' : 'border-gray-300 bg-gray-100 text-gray-800'}`}>
           {time.rawDate.getDate()}
         </div>
       )}

       {/* Hands inherit current color if set on parent, but let's be explicit */}
       <div 
         className={`absolute top-[25%] left-1/2 -ml-[3px] w-[6px] h-[25%] bg-current origin-bottom rounded-full shadow-lg transition-transform duration-1000 ease-linear ${mode === 'dark' ? 'text-white' : 'text-black'}`}
         style={{ transform: `rotate(${hourDeg}deg)`, ...colorStyle }}
       />
       <div 
         className={`absolute top-[10%] left-1/2 -ml-[2px] w-[4px] h-[40%] bg-current origin-bottom rounded-full shadow-lg transition-transform duration-1000 ease-linear ${mode === 'dark' ? 'text-white' : 'text-black'}`}
         style={{ transform: `rotate(${minuteDeg}deg)`, ...colorStyle }}
       />
       {settings.showSeconds && (
         <div 
           className={`absolute top-[10%] left-1/2 -ml-[1px] w-[2px] h-[45%] origin-bottom rounded-full shadow-sm transition-transform duration-1000 linear ${themeStyles.accentClass}`}
           style={{ transform: `rotate(${secondDeg}deg)` }}
         >
           <div className={`absolute -bottom-4 left-1/2 -ml-1.5 w-3 h-3 rounded-full ${themeStyles.accentClass}`} />
         </div>
       )}

       <div className={`absolute top-1/2 left-1/2 -ml-1.5 -mt-1.5 w-3 h-3 rounded-full ring-2 ring-white ${mode === 'dark' ? 'bg-black' : 'bg-black'}`}></div>
    </div>
  );
};

// --- 2. Retro Flip Clock ---
