export const NixieClock: React.FC<ClockFaceProps> = ({ time, themeStyles, settings }) => {
  // Nixie is complex with shadows, if custom color is set, we try to override text color and shadow.
  const colorStyle = settings.customColor ? { 
    color: settings.customColor,
    textShadow: `0 0 10px ${settings.customColor}, 0 0 20px ${settings.customColor}`
  } : {};

  const NixieDigit = ({ value }: { value: string }) => (
    <div className="relative w-16 h-28 sm:w-24 sm:h-40 bg-black/40 rounded-full border border-white/5 flex items-center justify-center shadow-[inset_0_0_20px_rgba(0,0,0,0.8)] overflow-hidden">
      <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-30 mix-blend-overlay"></div>
      <span className={`font-mono text-6xl sm:text-8xl z-10 ${themeStyles.textClass} animate-flicker`} style={colorStyle}>
        {value}
      </span>
      <span className="absolute font-mono text-6xl sm:text-8xl text-orange-900/20 blur-[1px] transform scale-90" style={{ color: settings.customColor ? settings.customColor : undefined, opacity: 0.2 }}>8</span>
    </div>
  );

  return (
    <div className="flex flex-col items-center justify-center gap-8 p-6 bg-black/80 rounded-xl border-4 border-gray-800 shadow-[0_0_50px_rgba(0,0,0,1)]">
      <div className="flex items-end gap-2 sm:gap-4">
        <div className="flex gap-2">
           {getDisplayHours(time.hours, settings.is24Hour).split('').map((d, i) => <NixieDigit key={`h-${i}`} value={d} />)}
        </div>

        <div className="flex flex-col gap-4 mb-8 sm:mb-12 animate-pulse">
           <div className="w-2 h-2 rounded-full bg-orange-500 shadow-[0_0_10px_orange]" style={{ backgroundColor: settings.customColor || undefined, boxShadow: settings.customColor ? `0 0 10px ${settings.customColor}` : undefined }}></div>
           <div className="w-2 h-2 rounded-full bg-orange-500 shadow-[0_0_10px_orange]" style={{ backgroundColor: settings.customColor || undefined, boxShadow: settings.customColor ? `0 0 10px ${settings.customColor}` : undefined }}></div>
        </div>

        <div className="flex gap-2">
           {pad(time.minutes).split('').map((d, i) => <NixieDigit key={`m-${i}`} value={d} />)}
        </div>

        {settings.showSeconds && (
          <>
            <div className="flex flex-col gap-4 mb-8 sm:mb-12 animate-pulse">
              <div className="w-2 h-2 rounded-full bg-orange-500 shadow-[0_0_10px_orange]" style={{ backgroundColor: settings.customColor || undefined, boxShadow: settings.customColor ? `0 0 10px ${settings.customColor}` : undefined }}></div>
              <div className="w-2 h-2 rounded-full bg-orange-500 shadow-[0_0_10px_orange]" style={{ backgroundColor: settings.customColor || undefined, boxShadow: settings.customColor ? `0 0 10px ${settings.customColor}` : undefined }}></div>
