              {pad(time.seconds).split('').map((d, i) => <NixieDigit key={`s-${i}`} value={d} />)}
            </div>
          </>
        )}
      </div>

      {settings.showDate && (
        <div 
          className="mt-4 px-6 py-2 border border-orange-900/50 rounded bg-black text-orange-700 font-mono text-sm tracking-widest shadow-[0_0_10px_rgba(255,100,0,0.1)]"
          style={{ borderColor: settings.customColor ? `${settings.customColor}40` : undefined, color: settings.customColor || undefined }}
        >
          {time.date.toUpperCase()}
        </div>
      )}
    </div>
  );
};

