import React, { useState, useEffect } from 'react';
import { useTime } from './hooks/useTime';
import { useAlarms } from './hooks/useAlarms';
import { THEMES } from './constants';
import { QuoteData, ClockSettings } from './types';
import { AppleClock, MicrosoftClock, JapanClock, IndiaClock, ChinaClock, FlipClock, NixieClock, SwissClock } from './components/ClockThemes';
import { AlarmManager } from './components/AlarmManager';
import { SettingsMenu } from './components/SettingsMenu';
import { getCulturalQuote } from './services/geminiService';

const App: React.FC = () => {
  const time = useTime();
  const [currentThemeId, setCurrentThemeId] = useState<string>('swiss');
  const [isWidgetMode, setIsWidgetMode] = useState<boolean>(false);
  const [themeMode, setThemeMode] = useState<'light' | 'dark'>('dark');
  const [quote, setQuote] = useState<QuoteData | null>(null);
  const [loadingQuote, setLoadingQuote] = useState<boolean>(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'themes' | 'alarms'>('themes');
  const [showWidgetControls, setShowWidgetControls] = useState(false);

  const [settings, setSettings] = useState<ClockSettings>({
    is24Hour: false,
    showSeconds: true,
    showDate: true,
    scale: 1,
    customColor: null
  });

  const { alarms, addAlarm, removeAlarm, toggleAlarm, triggeredAlarm, dismissAlarm } = useAlarms(time);

  const currentTheme = THEMES.find(t => t.id === currentThemeId) || THEMES[0];
  const currentStyles = currentTheme.modes[themeMode];

  useEffect(() => {
    // Save settings to local storage if needed, omitted for brevity
  }, [settings]);

  // Fetch a new quote when theme changes
  useEffect(() => {
    const fetchQuote = async () => {
      setLoadingQuote(true);
      const data = await getCulturalQuote(currentThemeId);
      setQuote(data);
      setLoadingQuote(false);
    };
    fetchQuote();
  }, [currentThemeId]);

  const toggleWidgetMode = () => {
    setIsWidgetMode(!isWidgetMode);
  };

  const navigateTheme = (direction: 'next' | 'prev') => {
    const currentIndex = THEMES.findIndex(t => t.id === currentThemeId);
    let newIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (newIndex >= THEMES.length) newIndex = 0;
    if (newIndex < 0) newIndex = THEMES.length - 1;
    setCurrentThemeId(THEMES[newIndex].id);
  };

  const renderClockFace = () => {
    const props = { time, mode: themeMode, themeStyles: currentStyles, settings };
    switch (currentThemeId) {
      case 'swiss': return <SwissClock {...props} />;
      case 'flip': return <FlipClock {...props} />;
      case 'nixie': return <NixieClock {...props} />;
      case 'apple': return <AppleClock {...props} />;
      case 'microsoft': return <MicrosoftClock {...props} />;
      case 'japan': return <JapanClock {...props} />;
      case 'india': return <IndiaClock {...props} />;
      case 'china': return <ChinaClock {...props} />;
      default: return <AppleClock {...props} />;
    }
  };

  return (
    <div className={`min-h-screen w-full flex items-center justify-center transition-all duration-700 ease-in-out bg-cover bg-center overflow-hidden ${isWidgetMode ? 'p-0' : 'p-4'}`}
         style={{ 
           backgroundImage: isWidgetMode ? 'none' : `url('https://picsum.photos/1920/1080?blur=10')`,
           backgroundColor: isWidgetMode ? 'transparent' : undefined
         }}
         onMouseEnter={() => isWidgetMode && setShowWidgetControls(true)}
         onMouseLeave={() => isWidgetMode && setShowWidgetControls(false)}
    >

      {/* Background Overlay for Main App Mode */}
      {!isWidgetMode && <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity duration-500"></div>}

      <SettingsMenu 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={settings} 
        onUpdate={setSettings}
        isDarkMode={themeMode === 'dark'}
      />

      {/* Alarm Overlay Modal */}
      {triggeredAlarm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in zoom-in duration-300">
           <div className={`p-8 rounded-2xl shadow-2xl flex flex-col items-center text-center max-w-sm w-full mx-4 border ${themeMode === 'dark' ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-200'}`}>
              <div className="w-16 h-16 rounded-full bg-red-500/20 flex items-center justify-center mb-4 animate-bounce">
                <svg className="w-8 h-8 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
              </div>
              <h2 className={`text-3xl font-bold mb-2 ${themeMode === 'dark' ? 'text-white' : 'text-slate-900'}`}>{time.hours}:{String(time.minutes).padStart(2,'0')}</h2>
              <p className={`text-lg mb-6 ${themeMode === 'dark' ? 'text-slate-300' : 'text-slate-600'}`}>{triggeredAlarm.label || "Alarm Triggered"}</p>
              <button 
                onClick={dismissAlarm}
                className="w-full py-3 bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl transition-colors shadow-lg shadow-red-500/30"
              >
                Dismiss
              </button>
           </div>
        </div>
      )}

      {/* --- WIDGET MODE CONTROL BAR --- */}
      {isWidgetMode && (
        <div 
          className={`fixed bottom-8 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2 px-4 py-2 rounded-full bg-black/50 backdrop-blur-xl border border-white/10 text-white transition-all duration-300 shadow-2xl
            ${showWidgetControls ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}
          `}
        >
          <button 
            onClick={() => navigateTheme('prev')}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
            title="Previous Theme"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>

          <div className="h-4 w-px bg-white/20 mx-1"></div>

          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
            title="Settings"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </button>

          <div className="h-4 w-px bg-white/20 mx-1"></div>

          <button 
            onClick={() => navigateTheme('next')}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
            title="Next Theme"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>

          <button 
            onClick={toggleWidgetMode}
            className="ml-2 px-3 py-1.5 bg-red-500/80 hover:bg-red-600 text-xs font-bold uppercase tracking-wider rounded-full transition-colors shadow-lg"
          >
            Exit
          </button>
        </div>
      )}


      {/* --- PREMIUM LAYOUT --- */}
      <div className={`relative flex w-full max-w-7xl h-[85vh] transition-all duration-500 ${isWidgetMode ? 'h-screen max-w-none' : ''}`}>

        {/* Floating Sidebar (Dock) */}
        {!isWidgetMode && (
          <div className={`
             absolute left-0 top-0 bottom-0 z-20 w-80 m-4 rounded-3xl backdrop-blur-xl border shadow-2xl flex flex-col overflow-hidden transition-all duration-300
             ${themeMode === 'dark' ? 'bg-slate-900/60 border-white/10 text-white' : 'bg-white/70 border-white/50 text-slate-800'}
          `}>
            {/* Header */}
            <div className="p-6 border-b border-white/5 flex items-center justify-between">
              <div>
                <h1 className="text-xl font-bold tracking-tight">ChronoVerse</h1>
                <p className="text-xs opacity-60">Premium Clock Engine</p>
              </div>
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="p-2 hover:bg-white/10 rounded-full transition-colors"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              </button>
            </div>

            {/* Navigation Tabs */}
            <div className="flex p-2 gap-2">
              <button 
                onClick={() => setActiveTab('themes')}
                className={`flex-1 py-2 text-xs font-semibold uppercase tracking-wider rounded-lg transition-all ${activeTab === 'themes' ? (themeMode === 'dark' ? 'bg-white/10 shadow-sm' : 'bg-white shadow-sm') : 'opacity-50 hover:opacity-100'}`}
              >
                Faces
              </button>
              <button 
                onClick={() => setActiveTab('alarms')}
                className={`flex-1 py-2 text-xs font-semibold uppercase tracking-wider rounded-lg transition-all ${activeTab === 'alarms' ? (themeMode === 'dark' ? 'bg-white/10 shadow-sm' : 'bg-white shadow-sm') : 'opacity-50 hover:opacity-100'}`}
              >
                Alarms
              </button>
            </div>

            {/* Content Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">

              {activeTab === 'themes' && (
                <div className="space-y-6">
                  {/* Category: Table Clocks */}
                  <div>
                    <h3 className="text-xs font-bold opacity-40 uppercase mb-3 ml-1">Table Top</h3>
                    <div className="grid grid-cols-1 gap-3">
                      {THEMES.filter(t => t.type === 'table').map(theme => (
                        <button
                          key={theme.id}
                          onClick={() => setCurrentThemeId(theme.id)}
                          className={`w-full text-left p-3 rounded-xl transition-all duration-200 flex items-center space-x-3 border group
                            ${currentThemeId === theme.id 
                              ? 'bg-blue-600 border-blue-500 shadow-lg shadow-blue-500/20 text-white' 
                              : `border-transparent hover:scale-[1.02] ${themeMode === 'dark' ? 'bg-white/5 hover:bg-white/10' : 'bg-white/40 hover:bg-white/60'}`}
                          `}
                        >
                           <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold ${currentThemeId === theme.id ? 'bg-white/20' : 'bg-black/10'}`}>
                             {theme.name.substring(0,1)}
                           </div>
                           <div>
                             <span className="block font-medium text-sm">{theme.name}</span>
                           </div>
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Category: Modern */}
                  <div>
                    <h3 className="text-xs font-bold opacity-40 uppercase mb-3 ml-1">Modern Digital</h3>
                    <div className="grid grid-cols-1 gap-3">
                      {THEMES.filter(t => t.type === 'modern').map(theme => (
                        <button
                          key={theme.id}
                          onClick={() => setCurrentThemeId(theme.id)}
                          className={`w-full text-left p-3 rounded-xl transition-all duration-200 flex items-center space-x-3 border group
                            ${currentThemeId === theme.id 
                              ? 'bg-blue-600 border-blue-500 shadow-lg shadow-blue-500/20 text-white' 
