import { useState, useEffect, useRef } from 'react';
import { Alarm, TimeState, AlarmSoundType } from '../types';

export const useAlarms = (currentTime: TimeState) => {
  const [alarms, setAlarms] = useState<Alarm[]>(() => {
    const saved = localStorage.getItem('chrono_alarms');
    return saved ? JSON.parse(saved) : [];
  });

  const [triggeredAlarm, setTriggeredAlarm] = useState<Alarm | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    localStorage.setItem('chrono_alarms', JSON.stringify(alarms));
  }, [alarms]);

  useEffect(() => {
    if (currentTime.seconds === 0) {
      const matchingAlarm = alarms.find(a => {
        const hours24 = currentTime.hours;
        const current24h = `${hours24.toString().padStart(2, '0')}:${currentTime.minutes.toString().padStart(2, '0')}`;
        return a.time === current24h && a.isActive;
      });

      if (matchingAlarm) {
        setTriggeredAlarm(matchingAlarm);
        playAlarmSound(matchingAlarm.sound);
      }
    }
  }, [currentTime.hours, currentTime.minutes, currentTime.seconds, alarms]);

  const addAlarm = (time: string, label: string, sound: AlarmSoundType = 'digital') => {
    const newAlarm: Alarm = {
      id: Date.now().toString(),
      time,
      label: label || 'Alarm',
      isActive: true,
      sound
    };
    setAlarms(prev => [...prev, newAlarm]);
  };

  const removeAlarm = (id: string) => {
    setAlarms(prev => prev.filter(a => a.id !== id));
  };

  const toggleAlarm = (id: string) => {
    setAlarms(prev => prev.map(a => a.id === id ? { ...a, isActive: !a.isActive } : a));
  };

  const dismissAlarm = () => {
    setTriggeredAlarm(null);
  };

  const snoozeAlarm = () => {
    if (!triggeredAlarm) return;

    // Calculate 5 minutes from now
    const now = new Date();
    now.setMinutes(now.getMinutes() + 5);
    const snoozeHours = now.getHours().toString().padStart(2, '0');
    const snoozeMinutes = now.getMinutes().toString().padStart(2, '0');
    const snoozeTime = `${snoozeHours}:${snoozeMinutes}`;

    // Add a temporary one-off alarm
    addAlarm(snoozeTime, `Snooze: ${triggeredAlarm.label}`, triggeredAlarm.sound);
    setTriggeredAlarm(null);
  };

  const playAlarmSound = (type: AlarmSoundType) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') ctx.resume();

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    const now = ctx.currentTime;

    if (type === 'digital') {
      // High pitch beeps
      osc.type = 'square';
      osc.frequency.setValueAtTime(880, now);
      osc.frequency.setValueAtTime(880, now + 0.1);
      osc.frequency.setValueAtTime(0, now + 0.11);
      osc.frequency.setValueAtTime(880, now + 0.2);
      osc.frequency.setValueAtTime(880, now + 0.3);

      gain.gain.setValueAtTime(0.1, now);
      gain.gain.linearRampToValueAtTime(0, now + 0.4);
      osc.start();
      osc.stop(now + 0.5);

    } else if (type === 'classic') {
      // Ringing bell modulation
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(600, now);
      osc.frequency.linearRampToValueAtTime(600, now + 1); // Sustain

      // Modulate amplitude rapidly to simulate ringing
      const lfo = ctx.createOscillator();
      lfo.type = 'square';
      lfo.frequency.value = 15; // 15Hz ringing
      const lfoGain = ctx.createGain();
      lfoGain.gain.value = 0.5;
      lfo.connect(lfoGain.gain);

      gain.gain.setValueAtTime(0.3, now);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 1.5);

      osc.start();
      osc.stop(now + 1.5);
      lfo.start();
      lfo.stop(now + 1.5);

    } else { // gentle
      // Soft sine wave swell
      osc.type = 'sine';
      osc.frequency.setValueAtTime(440, now);
      osc.frequency.exponentialRampToValueAtTime(523.25, now + 2); // A4 to C5

      gain.gain.setValueAtTime(0, now);
      gain.gain.linearRampToValueAtTime(0.2, now + 1);
      gain.gain.linearRampToValueAtTime(0, now + 2);

      osc.start();
      osc.stop(now + 2.1);
    }
  };

  return {
    alarms,
    addAlarm,
    removeAlarm,
    toggleAlarm,
    triggeredAlarm,
    dismissAlarm,
    snoozeAlarm
  };
};

import React, { useState } from 'react';
import { Alarm, AlarmSoundType } from '../types';

interface AlarmManagerProps {
  alarms: Alarm[];
  onAdd: (time: string, label: string, sound: AlarmSoundType) => void;
  onRemove: (id: string) => void;
  onToggle: (id: string) => void;
  isDarkMode: boolean;
}

export const AlarmManager: React.FC<AlarmManagerProps> = ({ alarms, onAdd, onRemove, onToggle, isDarkMode }) => {
  const [newTime, setNewTime] = useState('');
  const [newLabel, setNewLabel] = useState('');
  const [sound, setSound] = useState<AlarmSoundType>('digital');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTime) {
      onAdd(newTime, newLabel, sound);
      setNewTime('');
      setNewLabel('');
    }
  };

  const inputClass = `w-full bg-transparent border-b ${isDarkMode ? 'border-white/20 text-white placeholder-slate-500' : 'border-slate-300 text-slate-800 placeholder-slate-400'} focus:outline-none focus:border-blue-500 py-2 text-sm transition-colors`;
  const selectClass = `bg-transparent border-b ${isDarkMode ? 'border-white/20 text-white' : 'border-slate-300 text-slate-800'} py-2 text-sm focus:outline-none focus:border-blue-500`;

  return (
    <div className="space-y-4">
      <h2 className={`text-xs font-semibold uppercase tracking-wider ${isDarkMode ? 'text-slate-500' : 'text-slate-500'}`}>Alarms</h2>

      <form onSubmit={handleSubmit} className={`p-3 rounded-xl border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-slate-100 border-slate-200'} space-y-3`}>
        <div className="flex space-x-2">
          <input 
            type="time" 
            value={newTime}
            onChange={(e) => setNewTime(e.target.value)}
            required
            className={inputClass}
          />
          <input 
            type="text" 
            placeholder="Label"
            value={newLabel}
            onChange={(e) => setNewLabel(e.target.value)}
            className={inputClass}
          />
        </div>
        <div className="flex items-center space-x-2">
           <span className={`text-xs ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>Sound:</span>
           <select 
             value={sound} 
             onChange={(e) => setSound(e.target.value as AlarmSoundType)}
             className={`flex-1 ${selectClass}`}
           >
             <option value="digital" className="text-black">Digital Beep</option>
             <option value="classic" className="text-black">Classic Ring</option>
             <option value="gentle" className="text-black">Gentle Swell</option>
           </select>
        </div>
        <button 
          type="submit"
          className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold uppercase tracking-wider rounded-lg transition-colors"
        >
          Add Alarm
        </button>
      </form>

      <div className="space-y-2 max-h-48 overflow-y-auto pr-1 custom-scrollbar">
        {alarms.length === 0 && (
          <p className="text-xs text-center opacity-50 italic py-2">No alarms set</p>
        )}
        {alarms.map(alarm => (
          <div 
            key={alarm.id} 
            className={`flex items-center justify-between p-3 rounded-lg border transition-all ${
              isDarkMode 
                ? 'bg-white/5 border-white/5 hover:bg-white/10' 
                : 'bg-white border-slate-200 hover:bg-slate-50 shadow-sm'
            }`}
          >
            <div className="flex flex-col">
              <span className={`text-lg font-mono leading-none ${!alarm.isActive && 'opacity-50'} ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>
                {alarm.time}
              </span>
              <div className="flex items-center space-x-2">
                 <span className={`text-[10px] ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>{alarm.label}</span>
                 <span className={`text-[9px] uppercase px-1 rounded bg-current bg-opacity-10 ${isDarkMode ? 'text-slate-500' : 'text-slate-400'}`}>{alarm.sound}</span>
              </div>
            </div>

            <div className="flex items-center space-x-3">
              <button 
                onClick={() => onToggle(alarm.id)}
                className={`w-8 h-4 rounded-full relative transition-colors ${alarm.isActive ? 'bg-blue-500' : (isDarkMode ? 'bg-slate-700' : 'bg-slate-300')}`}
              >
                <div className={`absolute top-0.5 w-3 h-3 rounded-full bg-white transition-transform ${alarm.isActive ? 'left-4.5 translate-x-1' : 'left-0.5'}`}></div>
              </button>
              <button 
                onClick={() => onRemove(alarm.id)}
                className="text-slate-500 hover:text-red-500 transition-colors"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          </div>
        ))}
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #475569; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
      `}</style>
    </div>
  );
};

import React from 'react';
import { TimeState, ThemeModeData, ClockSettings } from '../types';

interface ClockFaceProps {
  time: TimeState;
  mode: 'light' | 'dark';
  themeStyles: ThemeModeData;
  settings: ClockSettings;
}

// Helper to format hours based on settings
const getDisplayHours = (hours: number, is24Hour: boolean): string => {
  if (is24Hour) return hours.toString().padStart(2, '0');
  const h = hours % 12 || 12;
  return h.toString().padStart(2, '0');
};

const pad = (num: number) => num.toString().padStart(2, '0');

const useColorStyle = (customColor: string | null) => {
  return customColor ? { color: customColor } : {};
};

// Wrapper for entrance animations
const AnimatedWrapper: React.FC<{children: React.ReactNode}> = ({ children }) => (
  <div className="w-full h-full flex items-center justify-center animate-in fade-in zoom-in duration-700 ease-out">
    {children}
  </div>
);

// --- 4. Word Clock (New) ---
export const WordClock: React.FC<ClockFaceProps> = ({ time, mode, themeStyles, settings }) => {
  const colorStyle = useColorStyle(settings.customColor);

  // Logic to determine active words
  const m = time.minutes;
  const h = time.hours % 12 || 12;
  const nextH = (time.hours + 1) % 12 || 12;

  const isHalf = m >= 30 && m < 35;
  const isTenPast = m >= 10 && m < 15;
  const isTenTo = m >= 50 && m < 55;
  const isQuarterPast = m >= 15 && m < 20;
  const isQuarterTo = m >= 45 && m < 50;
  const isOClock = m < 5;
  const isPast = m >= 5 && m < 35;
  const isTo = m >= 35;

  const activeHour = isTo ? nextH : h;

  const Word = ({ text, active }: { text: string, active: boolean }) => (
    <span 
      className={`transition-all duration-500 ${active ? themeStyles.accentClass : 'opacity-20 blur-[0.5px]'}`}
      style={active ? { ...colorStyle, textShadow: settings.customColor ? `0 0 15px ${settings.customColor}` : undefined } : undefined}
    >
      {text}
    </span>
  );

  return (
    <AnimatedWrapper>
      <div className={`grid grid-cols-6 gap-x-4 gap-y-2 text-2xl sm:text-4xl font-mono leading-relaxed text-center ${themeStyles.textClass}`}>
         <div className="col-span-6 flex justify-between px-8">
            <Word text="IT" active={true} />
            <Word text="IS" active={true} />
            <Word text="HALF" active={isHalf} />
            <Word text="TEN" active={isTenPast || isTenTo} />
         </div>
         <div className="col-span-6 flex justify-between px-4">
            <Word text="QUARTER" active={isQuarterPast || isQuarterTo} />
            <Word text="TWENTY" active={(m >= 20 && m < 30) || (m >= 40 && m < 45)} />
         </div>
         <div className="col-span-6 flex justify-between px-8">
            <Word text="FIVE" active={(m >= 5 && m < 10) || (m >= 25 && m < 30) || (m >= 35 && m < 40) || (m >= 55)} />
            <Word text="MINUTES" active={!isOClock && !isHalf && !isQuarterPast && !isQuarterTo} /> 
         </div>
         <div className="col-span-6 flex justify-center gap-8">
            <Word text="PAST" active={isPast && !isOClock} />
            <Word text="TO" active={isTo && !isOClock} />
         </div>
         <div className="col-span-6 flex flex-wrap justify-center gap-4 px-4 mt-2 font-bold">
            <Word text="ONE" active={activeHour === 1} />
            <Word text="TWO" active={activeHour === 2} />
            <Word text="THREE" active={activeHour === 3} />
            <Word text="FOUR" active={activeHour === 4} />
            <Word text="FIVE" active={activeHour === 5} />
            <Word text="SIX" active={activeHour === 6} />
            <Word text="SEVEN" active={activeHour === 7} />
            <Word text="EIGHT" active={activeHour === 8} />
            <Word text="NINE" active={activeHour === 9} />
            <Word text="TEN" active={activeHour === 10} />
            <Word text="ELEVEN" active={activeHour === 11} />
            <Word text="TWELVE" active={activeHour === 12} />
         </div>
         <div className="col-span-6 flex justify-center mt-2">
            <Word text="O'CLOCK" active={isOClock} />
         </div>
      </div>
    </AnimatedWrapper>
  );
};

// --- 5. Binary Clock (New) ---
export const BinaryClock: React.FC<ClockFaceProps> = ({ time, themeStyles, settings }) => {
  const colorStyle = useColorStyle(settings.customColor);

  // Split time into digits: HH MM SS -> h1 h2 : m1 m2 : s1 s2
  const hStr = getDisplayHours(time.hours, settings.is24Hour);
  const mStr = pad(time.minutes);
  const sStr = pad(time.seconds);

  const digits = [
    parseInt(hStr[0]), parseInt(hStr[1]),
    parseInt(mStr[0]), parseInt(mStr[1]),
    parseInt(sStr[0]), parseInt(sStr[1])
  ];

  // 8, 4, 2, 1
  const rows = [8, 4, 2, 1];

  return (
    <AnimatedWrapper>
      <div className={`flex gap-4 sm:gap-8 p-8 rounded-xl ${themeStyles.containerClass}`}>
        {digits.map((digit, colIndex) => (
          <div key={colIndex} className={`flex flex-col gap-3 ${colIndex % 2 === 1 && colIndex !== 5 ? 'mr-4 sm:mr-8' : ''}`}>
             {rows.map((val) => {
               const isOn = (digit & val) === val;
               return (
                 <div 
                   key={val} 
                   className={`w-8 h-8 sm:w-12 sm:h-12 rounded-full transition-all duration-300 transform ${isOn ? `scale-110 ${themeStyles.accentClass}` : `scale-90 opacity-20 ${themeStyles.textClass}`}`}
                   style={isOn ? { ...colorStyle, backgroundColor: settings.customColor || undefined, boxShadow: settings.customColor ? `0 0 10px ${settings.customColor}` : undefined } : undefined}
                 >
                 </div>
               );
             })}
             <div className={`text-center font-mono mt-2 opacity-50 ${themeStyles.subTextClass}`}>
               {digit}
             </div>
          </div>
        ))}
      </div>
    </AnimatedWrapper>
  );
};


