                    <div className="grid grid-cols-1 gap-3">
                      {THEMES.filter(t => t.type === 'cultural').map(theme => (
                        <button
                          key={theme.id}
                          onClick={() => setCurrentThemeId(theme.id)}
                          className={`w-full text-left p-3 rounded-xl transition-all duration-200 flex items-center space-x-3 border group
                            ${currentThemeId === theme.id 
                              ? 'bg-blue-600 border-blue-500 shadow-lg shadow-blue-500/20 text-white' 
                              : `border-transparent hover:scale-[1.02] ${themeMode === 'dark' ? 'bg-white/5 hover:bg-white/10' : 'bg-white/40 hover:bg-white/60'}`}
                          `}
                        >
                           <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold ${currentThemeId === theme.id ? 'bg-white/20' : 'bg-black/10'}`}>
                             {theme.name.substring(0,1)}
                           </div>
                           <div>
                             <span className="block font-medium text-sm">{theme.name}</span>
                           </div>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}

              {activeTab === 'alarms' && (
                <AlarmManager 
                  alarms={alarms} 
                  onAdd={addAlarm} 
                  onRemove={removeAlarm} 
                  onToggle={toggleAlarm}
                  isDarkMode={themeMode === 'dark'}
                />
              )}
            </div>

            {/* Footer */}
            <div className="p-4 border-t border-white/5 space-y-3">
               <div className={`rounded-lg p-3 text-xs border ${themeMode === 'dark' ? 'bg-black/20 border-white/5' : 'bg-white/40 border-black/5'}`}>
                 <div className="flex items-center gap-2 mb-1 opacity-70 font-semibold">
                   <span>AI Insight</span>
                 </div>
                 <p className="italic opacity-80 leading-relaxed">"{quote?.text}"</p>
               </div>

               <div className="grid grid-cols-2 gap-2">
                 <button 
                   onClick={() => setThemeMode(prev => prev === 'light' ? 'dark' : 'light')}
                   className={`py-2 rounded-lg text-xs font-medium transition-colors border flex items-center justify-center gap-2
                     ${themeMode === 'dark' ? 'bg-white/10 hover:bg-white/20 border-white/5' : 'bg-white/50 hover:bg-white/80 border-black/5'}
                   `}
                 >
                   {themeMode === 'dark' ? 'Light Mode' : 'Dark Mode'}
                 </button>
                 <button 
                  onClick={toggleWidgetMode}
                  className={`py-2 rounded-lg text-xs font-medium transition-colors border flex items-center justify-center gap-2
                    ${themeMode === 'dark' ? 'bg-white/10 hover:bg-white/20 border-white/5' : 'bg-white/50 hover:bg-white/80 border-black/5'}
                  `}
                 >
                   Widget Mode
                 </button>
               </div>
            </div>
          </div>
        )}

        {/* Main Clock Stage */}
        <div className={`
            flex-1 relative flex items-center justify-center transition-all duration-500
            ${!isWidgetMode ? 'ml-0 lg:ml-[340px]' : ''}
        `}>

          <div className={`
             relative w-full h-full flex items-center justify-center transition-all duration-700
             ${!isWidgetMode ? 'scale-90 opacity-100' : 'opacity-100'}
          `}>
             {/* Clock Wrapper with Scale Transform */}
             <div 
               className={`
                 transition-all duration-500 origin-center
                 ${isWidgetMode ? 'w-full h-full' : (currentTheme.type === 'table' ? 'w-full h-full flex items-center justify-center' : 'w-full max-w-4xl aspect-video shadow-2xl rounded-3xl overflow-hidden')}
                 ${!isWidgetMode && currentTheme.type !== 'table' ? currentStyles.containerClass : ''}
               `}
               style={{ transform: `scale(${settings.scale})` }}
             >
               {renderClockFace()}
             </div>
          </div>

        </div>
      </div>
    </div>
  );
};

