import { useState, useEffect, useRef, useCallback } from 'react';
import { Alarm, TimeState, AlarmSoundType } from '../types';

export const useAlarms = (currentTime: TimeState) => {
  const [alarms, setAlarms] = useState<Alarm[]>(() => {
    try {
      const saved = localStorage.getItem('chrono_alarms');
      return saved ? JSON.parse(saved) : [];
    } catch {
      return [];
    }
  });

  const [triggeredAlarm, setTriggeredAlarm] = useState<Alarm | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    localStorage.setItem('chrono_alarms', JSON.stringify(alarms));
  }, [alarms]);

  const checkAlarmTrigger = useCallback(() => {
    // Only check when seconds are 0 to avoid multiple triggers per minute
    if (currentTime.seconds !== 0) return;

    const currentDay = currentTime.rawDate.getDay(); // 0 = Sunday
    const hours24 = currentTime.hours;
    const current24h = `${hours24.toString().padStart(2, '0')}:${currentTime.minutes.toString().padStart(2, '0')}`;

    const matchingAlarm = alarms.find(a => {
      if (!a.isActive) return false;
      if (a.time !== current24h) return false;

      // If repeatDays is empty, it's a one-time alarm (triggers any day it matches)
      // If repeatDays has values, current day must be in it.
      if (a.repeatDays.length > 0 && !a.repeatDays.includes(currentDay)) {
        return false;
      }
      return true;
    });

    if (matchingAlarm) {
      setTriggeredAlarm(matchingAlarm);
      playAlarmSound(matchingAlarm.sound);

      // If it's a one-time alarm, deactivate it after triggering
      if (matchingAlarm.repeatDays.length === 0) {
        toggleAlarm(matchingAlarm.id, false);
      }
    }
  }, [currentTime.hours, currentTime.minutes, currentTime.seconds, currentTime.rawDate, alarms]);

  useEffect(() => {
    checkAlarmTrigger();
  }, [checkAlarmTrigger]);

  const addAlarm = (time: string, label: string, sound: AlarmSoundType, repeatDays: number[] = [], snoozeDuration: number = 5) => {
    const newAlarm: Alarm = {
      id: Date.now().toString(),
      time,
      label: label || 'Alarm',
      isActive: true,
      sound,
      repeatDays,
      snoozeDuration
    };
    setAlarms(prev => [...prev, newAlarm]);
  };

  const removeAlarm = (id: string) => {
    setAlarms(prev => prev.filter(a => a.id !== id));
  };

  const toggleAlarm = (id: string, forceState?: boolean) => {
    setAlarms(prev => prev.map(a => a.id === id ? { ...a, isActive: forceState !== undefined ? forceState : !a.isActive } : a));
  };

  const dismissAlarm = () => {
    setTriggeredAlarm(null);
  };

  const snoozeAlarm = () => {
    if (!triggeredAlarm) return;

    // Calculate snooze time
    const now = new Date();
    now.setMinutes(now.getMinutes() + triggeredAlarm.snoozeDuration);
    const snoozeHours = now.getHours().toString().padStart(2, '0');
    const snoozeMinutes = now.getMinutes().toString().padStart(2, '0');
    const snoozeTime = `${snoozeHours}:${snoozeMinutes}`;

    // Add a temporary one-off alarm (snooze is always one-time)
    addAlarm(snoozeTime, `Snooze: ${triggeredAlarm.label}`, triggeredAlarm.sound, [], triggeredAlarm.snoozeDuration);
    setTriggeredAlarm(null);
  };

  const playAlarmSound = (type: AlarmSoundType) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') ctx.resume();

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    const now = ctx.currentTime;

    if (type === 'digital') {
      // High pitch beeps
      osc.type = 'square';
      osc.frequency.setValueAtTime(880, now);
      osc.frequency.setValueAtTime(880, now + 0.1);
      osc.frequency.setValueAtTime(0, now + 0.11);
      osc.frequency.setValueAtTime(880, now + 0.2);
      osc.frequency.setValueAtTime(880, now + 0.3);

      gain.gain.setValueAtTime(0.1, now);
      gain.gain.linearRampToValueAtTime(0, now + 0.4);
      osc.start();
      osc.stop(now + 0.5);

    } else if (type === 'classic') {
      // Ringing bell modulation
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(600, now);

      const lfo = ctx.createOscillator();
      lfo.type = 'square';
      lfo.frequency.value = 15;
      const lfoGain = ctx.createGain();
      lfoGain.gain.value = 0.5;
      lfo.connect(lfoGain.gain);

      gain.gain.setValueAtTime(0.2, now);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 1.5);

      osc.start();
      osc.stop(now + 1.5);
      lfo.start();
      lfo.stop(now + 1.5);

    } else { // gentle
      // Soft sine swell
      osc.type = 'sine';
      osc.frequency.setValueAtTime(440, now);
      osc.frequency.exponentialRampToValueAtTime(523.25, now + 2);

      gain.gain.setValueAtTime(0, now);
      gain.gain.linearRampToValueAtTime(0.2, now + 1);
      gain.gain.linearRampToValueAtTime(0, now + 2);

      osc.start();
      osc.stop(now + 2.1);
    }
  };

  return {
    alarms,
    addAlarm,
    removeAlarm,
    toggleAlarm,
    triggeredAlarm,
    dismissAlarm,
    snoozeAlarm
  };
};

import React, { useState } from 'react';
import { ClockSettings } from '../types';

interface SettingsMenuProps {
  settings: ClockSettings;
  onUpdate: (newSettings: ClockSettings) => void;
  isOpen: boolean;
  onClose: () => void;
  isDarkMode: boolean;
}

const COLORS = [
  { label: 'Default', value: null },
  { label: 'White', value: '#ffffff' },
  { label: 'Red', value: '#ef4444' },
  { label: 'Orange', value: '#f97316' },
  { label: 'Amber', value: '#f59e0b' },
  { label: 'Green', value: '#22c55e' },
  { label: 'Blue', value: '#3b82f6' },
  { label: 'Purple', value: '#a855f7' },
  { label: 'Pink', value: '#ec4899' },
];

export const SettingsMenu: React.FC<SettingsMenuProps> = ({ settings, onUpdate, isOpen, onClose, isDarkMode }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'appearance' | 'alarms'>('general');

  if (!isOpen) return null;

  const updateSetting = <K extends keyof ClockSettings>(key: K, value: ClockSettings[K]) => {
    onUpdate({ ...settings, [key]: value });
  };

  const bgClass = isDarkMode ? 'bg-slate-900/95 text-white' : 'bg-white/95 text-slate-800';
  const borderClass = isDarkMode ? 'border-white/10' : 'border-slate-200';
  const tabClass = (tab: string) => `pb-2 px-1 text-xs font-semibold uppercase tracking-wider border-b-2 transition-colors ${activeTab === tab ? 'border-blue-500 opacity-100' : 'border-transparent opacity-50 hover:opacity-80'}`;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
      <div 
        className={`w-full max-w-sm rounded-2xl shadow-2xl border ${bgClass} ${borderClass} transform transition-all scale-100 max-h-[90vh] overflow-hidden flex flex-col`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-6 pb-0 flex justify-between items-center">
          <h2 className="text-xl font-bold tracking-tight">Settings</h2>
          <button onClick={onClose} className="p-2 hover:bg-black/5 rounded-full transition-colors">
            <svg className="w-5 h-5 opacity-60" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Tabs */}
        <div className="flex space-x-4 px-6 mt-4 border-b border-white/5">
          <button onClick={() => setActiveTab('general')} className={tabClass('general')}>General</button>
          <button onClick={() => setActiveTab('appearance')} className={tabClass('appearance')}>Appearance</button>
          <button onClick={() => setActiveTab('alarms')} className={tabClass('alarms')}>Defaults</button>
        </div>

        <div className="p-6 overflow-y-auto custom-scrollbar flex-1 space-y-6">

          {/* GENERAL TAB */}
          {activeTab === 'general' && (
            <div className="space-y-4">
              <ToggleRow label="24-Hour Clock" checked={settings.is24Hour} onChange={(v) => updateSetting('is24Hour', v)} />
              <ToggleRow label="Show Seconds" checked={settings.showSeconds} onChange={(v) => updateSetting('showSeconds', v)} />
              <ToggleRow label="Show Date" checked={settings.showDate} onChange={(v) => updateSetting('showDate', v)} />
            </div>
          )}

          {/* APPEARANCE TAB */}
          {activeTab === 'appearance' && (
            <div className="space-y-6">
               <div className="space-y-3">
                 <div className="flex justify-between items-center">
                   <span className="font-medium text-sm">Base Scale</span>
                   <span className="text-xs opacity-60">{Math.round(settings.scale * 100)}%</span>
                 </div>
                 <input 
                   type="range" min="0.5" max="1.5" step="0.05"
                   value={settings.scale}
                   onChange={(e) => updateSetting('scale', parseFloat(e.target.value))}
                   className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer dark:bg-slate-700 accent-blue-500"
                 />
               </div>

               <div className="space-y-3">
                 <span className="font-medium text-sm">Accent Color</span>
                 <ColorPicker selected={settings.customColor} onSelect={(c) => updateSetting('customColor', c)} />
               </div>

               <div className="border-t border-white/10 pt-4 space-y-4">
                  <div className="flex items-center justify-between">
                     <span className="font-medium text-sm">Widget Overrides</span>
                     <Toggle checked={settings.enableWidgetOverrides} onChange={(v) => updateSetting('enableWidgetOverrides', v)} />
                  </div>

                  {settings.enableWidgetOverrides && (
                    <div className="pl-4 border-l-2 border-blue-500/30 space-y-4 animate-in slide-in-from-left-2 duration-200">
                      <div className="space-y-2">
                        <div className="flex justify-between items-center">
                          <span className="text-xs font-medium opacity-80">Widget Scale</span>
                          <span className="text-xs opacity-60">{Math.round(settings.widgetScale * 100)}%</span>
                        </div>
                        <input 
                          type="range" min="0.5" max="2.0" step="0.05"
                          value={settings.widgetScale}
                          onChange={(e) => updateSetting('widgetScale', parseFloat(e.target.value))}
                          className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer dark:bg-slate-700 accent-blue-500"
                        />
                      </div>
                      <div className="space-y-2">
                        <span className="text-xs font-medium opacity-80">Widget Color</span>
                        <ColorPicker selected={settings.widgetColor} onSelect={(c) => updateSetting('widgetColor', c)} small />
                      </div>
                    </div>
                  )}
               </div>
            </div>
          )}

          {/* ALARMS TAB */}
          {activeTab === 'alarms' && (
            <div className="space-y-4">
               <div className="space-y-2">
                 <span className="font-medium text-sm">Default Snooze (Minutes)</span>
                 <div className="flex gap-2">
                   {[5, 10, 15].map(min => (
                     <button
                       key={min}
                       onClick={() => updateSetting('defaultSnoozeMinutes', min)}
                       className={`flex-1 py-2 text-xs font-bold rounded-lg border transition-all ${
                         settings.defaultSnoozeMinutes === min 
                           ? 'bg-blue-600 border-blue-500 text-white' 
                           : 'border-white/10 hover:bg-white/5 opacity-70'
                       }`}
                     >
                       {min}m
                     </button>
                   ))}
                 </div>
               </div>
            </div>
          )}

        </div>
        <div className="p-4 border-t border-white/5 text-center bg-black/5">
            <p className="text-[10px] opacity-40 font-mono">ChronoVerse Build 2.0</p>
        </div>
      </div>
    </div>
  );
};

