import React, { useState, useEffect, useCallback } from 'react';
import { useTime } from './hooks/useTime';
import { useAlarms } from './hooks/useAlarms';
import { THEMES } from './constants';
import { QuoteData, ClockSettings, ThemeCategory } from './types';
import { AppleClock, MicrosoftClock, JapanClock, IndiaClock, ChinaClock, FlipClock, NixieClock, SwissClock, WordClock, BinaryClock, WashiClock, JaliClock, GalaxyClock, NasaClock } from './components/ClockThemes';
import { AlarmManager } from './components/AlarmManager';
import { SettingsMenu } from './components/SettingsMenu';
import { getCulturalQuote } from './services/geminiService';

const App: React.FC = () => {
  const time = useTime();
  const [currentThemeId, setCurrentThemeId] = useState<string>('swiss');
  const [isWidgetMode, setIsWidgetMode] = useState<boolean>(false);
  const [quote, setQuote] = useState<QuoteData | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'themes' | 'alarms'>('themes');
  const [showWidgetControls, setShowWidgetControls] = useState(false);

  // Shuffle State
  const [shuffleIntervalMs, setShuffleIntervalMs] = useState<number | null>(null); // null means OFF
  const [showShuffleMenu, setShowShuffleMenu] = useState(false);
  const [customShuffleMinutes, setCustomShuffleMinutes] = useState<string>('30');

  const currentTheme = THEMES.find(t => t.id === currentThemeId) || THEMES[0];

  // Background Transition State
  const [activeBg, setActiveBg] = useState(currentTheme.backgroundImage);
  const [nextBg, setNextBg] = useState<string | null>(null);

  const [settings, setSettings] = useState<ClockSettings>({
    is24Hour: false,
    showSeconds: true,
    showDate: true,
    scale: 1,
    customColor: null,
    themeMode: 'dark',
    enableWidgetOverrides: false,
    widgetScale: 1.0,
    widgetColor: null,
    defaultSnoozeMinutes: 5,
  });

  const { alarms, addAlarm, removeAlarm, toggleAlarm, triggeredAlarm, dismissAlarm, snoozeAlarm } = useAlarms(time);
  const currentStyles = currentTheme.modes[settings.themeMode];

  // Group themes by category for sidebar
  const themesByCategory = THEMES.reduce((acc, theme) => {
    const cat = theme.category;
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(theme);
    return acc;
  }, {} as Record<ThemeCategory, typeof THEMES>);

  useEffect(() => {
    // Quote fetching
    const fetchQuote = async () => {
      if (currentTheme.type === 'cultural' || currentTheme.id === 'apple' || currentTheme.id === 'microsoft') {
        const data = await getCulturalQuote(currentThemeId);
        setQuote(data);
      } else {
        setQuote({ text: currentTheme.description, author: "ChronoVerse" });
      }
    };
    fetchQuote();

    // Handle Background Transition
    if (currentTheme.backgroundImage !== activeBg && currentTheme.backgroundImage !== nextBg) {
       setNextBg(currentTheme.backgroundImage);
       const timer = setTimeout(() => {
         setActiveBg(currentTheme.backgroundImage);
         setNextBg(null);
       }, 800); // Matches CSS duration
       return () => clearTimeout(timer);
    }
  }, [currentThemeId, currentTheme.backgroundImage]); // eslint-disable-line

  // Shuffle Logic
  const navigateTheme = useCallback((direction: 'next' | 'prev') => {
    const currentIndex = THEMES.findIndex(t => t.id === currentThemeId);
    let newIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (newIndex >= THEMES.length) newIndex = 0;
    if (newIndex < 0) newIndex = THEMES.length - 1;
    setCurrentThemeId(THEMES[newIndex].id);
  }, [currentThemeId]);

  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (shuffleIntervalMs) {
      interval = setInterval(() => {
        navigateTheme('next');
      }, shuffleIntervalMs);
    }
    return () => clearInterval(interval);
  }, [shuffleIntervalMs, navigateTheme]);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setIsSettingsOpen(false);
        if (isWidgetMode) setIsWidgetMode(false);
        setShowShuffleMenu(false);
      }
      if (!isWidgetMode && !isSettingsOpen) {
        if (e.key === '1') setActiveTab('themes');
        if (e.key === '2') setActiveTab('alarms');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isWidgetMode, isSettingsOpen]);

  const toggleWidgetMode = () => setIsWidgetMode(!isWidgetMode);
  const toggleThemeMode = () => setSettings(s => ({...s, themeMode: s.themeMode === 'light' ? 'dark' : 'light'}));

  const setShuffle = (minutes: number | null) => {
    if (minutes === null) {
      setShuffleIntervalMs(null);
    } else {
      setShuffleIntervalMs(minutes * 60 * 1000);
    }
    setShowShuffleMenu(false);
  };

  const renderClockFace = () => {
    // Calculate overrides
    const useOverride = isWidgetMode && settings.enableWidgetOverrides;
    const finalScale = useOverride ? settings.widgetScale : settings.scale;
    const finalColor = useOverride ? settings.widgetColor : settings.customColor;

    const props = { 
      time, 
      mode: settings.themeMode, 
      themeStyles: currentStyles, 
      settings,
      overrideScale: finalScale,
      overrideColor: finalColor
    };

    // Use key to force re-animation when theme changes
    const KeyedComponent = (Component: React.FC<any>) => <Component key={currentThemeId} {...props} />;

    switch (currentThemeId) {
      case 'swiss': return KeyedComponent(SwissClock);
      case 'flip': return KeyedComponent(FlipClock);
      case 'nixie': return KeyedComponent(NixieClock);
      case 'galaxy': return KeyedComponent(GalaxyClock);
      case 'word': return KeyedComponent(WordClock);
      case 'binary': return KeyedComponent(BinaryClock);
      case 'apple': return KeyedComponent(AppleClock);
      case 'microsoft': return KeyedComponent(MicrosoftClock);
      case 'nasa': return KeyedComponent(NasaClock);
      case 'japan': return KeyedComponent(JapanClock);
      case 'washi': return KeyedComponent(WashiClock);
      case 'india': return KeyedComponent(IndiaClock);
      case 'jali': return KeyedComponent(JaliClock);
      case 'china': return KeyedComponent(ChinaClock);
      default: return KeyedComponent(AppleClock);
    }
  };

  const isDark = settings.themeMode === 'dark';

  return (
    <div className={`min-h-screen w-full flex items-center justify-center bg-cover bg-center overflow-hidden relative transition-all duration-300 font-sans ${isWidgetMode ? 'p-0' : 'p-4'}`}
         onMouseEnter={() => isWidgetMode && setShowWidgetControls(true)}
         onMouseLeave={() => isWidgetMode && setShowWidgetControls(false)}
    >

      {/* Smooth Background System */}
      <div 
         className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000 ease-in-out z-0"
         style={{ backgroundImage: `url('${activeBg}')`, opacity: isWidgetMode ? 0 : 1 }}
      />
      {nextBg && (
        <div 
          className="absolute inset-0 bg-cover bg-center animate-in fade-in duration-1000 ease-in-out z-0"
          style={{ backgroundImage: `url('${nextBg}')`, opacity: isWidgetMode ? 0 : 1 }}
        />
      )}

      <div className={`absolute inset-0 transition-all duration-1000 z-0 ${isWidgetMode ? '' : (isDark ? 'bg-black/60 backdrop-blur-md' : 'bg-white/40 backdrop-blur-md')}`}></div>

      <SettingsMenu 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={settings} 
        onUpdate={setSettings}
        isDarkMode={isDark}
      />

      {/* Alarm Notification Overlay */}
      {triggeredAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-xl animate-in fade-in zoom-in duration-300">
           <div className={`p-8 rounded-3xl shadow-2xl flex flex-col items-center text-center max-w-sm w-full mx-4 border ${isDark ? 'bg-slate-900 border-white/10 text-white' : 'bg-white border-slate-200 text-slate-900'}`}>
              <div className="w-20 h-20 rounded-full bg-red-500/20 flex items-center justify-center mb-6 animate-pulse">
                <svg className="w-10 h-10 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
              </div>
              <h2 className="text-5xl font-light mb-2">{time.hours}:{String(time.minutes).padStart(2,'0')}</h2>
              <p className="text-xl opacity-70 mb-8 font-medium">{triggeredAlarm.label || "Time is up"}</p>

              <div className="flex gap-4 w-full">
                <button 
                  onClick={snoozeAlarm}
                  className="flex-1 py-4 bg-white/10 hover:bg-white/20 backdrop-blur border border-white/10 font-bold rounded-2xl transition-all"
                >
                  Snooze
                </button>
                <button 
                  onClick={dismissAlarm}
                  className="flex-1 py-4 bg-red-500 hover:bg-red-600 text-white font-bold rounded-2xl transition-all shadow-lg shadow-red-500/40"
                >
                  Dismiss
                </button>
              </div>
           </div>
        </div>
      )}

      {/* Widget Control Bar (Hover) */}
      {isWidgetMode && (
        <div 
          className={`fixed top-8 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center transition-all duration-300
            ${showWidgetControls || showShuffleMenu ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}
          `}
        >
          <div className="flex items-center gap-1 px-3 py-2 rounded-full bg-black/60 backdrop-blur-xl border border-white/10 text-white shadow-2xl">
            <ControlBtn onClick={() => navigateTheme('prev')} icon={<path d="M15 19l-7-7 7-7" />} label="Prev" />
            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <ControlBtn onClick={() => navigateTheme('next')} icon={<path d="M9 5l7 7-7 7" />} label="Next" />
            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <div className="relative">
              <ControlBtn 
                onClick={() => setShowShuffleMenu(!showShuffleMenu)} 
                icon={shuffleIntervalMs !== null
                  ? <path d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" className="animate-spin" />
                  : <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                }
                label={shuffleIntervalMs ? "Shuffle On" : "Shuffle"}
                active={shuffleIntervalMs !== null}
              />
              {/* Shuffle Menu Popover */}
              {showShuffleMenu && (
                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-3 w-40 bg-slate-800 border border-white/10 rounded-xl shadow-xl p-2 flex flex-col gap-1 z-50 animate-in slide-in-from-top-2">
                  <div className="text-[10px] text-white/50 px-2 py-1 uppercase tracking-wider font-bold">Interval</div>
                  {[5, 10, 15].map(min => (
                    <button 
                      key={min} 
                      onClick={() => setShuffle(min)}
                      className={`text-left px-3 py-2 rounded-lg text-xs font-bold transition-colors ${shuffleIntervalMs === min * 60000 ? 'bg-blue-600 text-white' : 'text-white hover:bg-white/10'}`}
                    >
                      Every {min} min
                    </button>
                  ))}
                  <div className="h-px bg-white/10 my-1"></div>
                   <div className="flex items-center gap-2 px-2 pb-1">
                      <input 
                        type="number" 
                        min="1" 
                        max="60"
                        className="w-12 bg-black/20 text-white text-xs p-1 rounded border border-white/10 text-center"
                        value={customShuffleMinutes}
                        onChange={(e) => setCustomShuffleMinutes(e.target.value)}
                      />
                      <button 
                        onClick={() => setShuffle(parseInt(customShuffleMinutes) || 5)}
                        className="text-[10px] bg-white/10 hover:bg-white/20 px-2 py-1.5 rounded text-white"
                      >
                        Set Min
                      </button>
                   </div>
                   {shuffleIntervalMs !== null && (
                     <button onClick={() => setShuffle(null)} className="mt-1 text-xs text-red-400 hover:bg-red-500/10 py-2 rounded-lg font-bold">Stop Shuffle</button>
                   )}
                </div>
              )}
            </div>

            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <ControlBtn 
              onClick={toggleThemeMode} 
              icon={isDark 
                ? <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
                : <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
              } 
              label={isDark ? "Light Mode" : "Dark Mode"} 
            />
            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <ControlBtn onClick={() => setIsSettingsOpen(true)} icon={<path d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />} label="Settings" />
            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <button onClick={toggleWidgetMode} className="ml-1 px-3 py-1 bg-red-500/80 hover:bg-red-600 text-[10px] font-bold uppercase rounded-full transition-colors shadow-lg">Exit</button>
          </div>
        </div>
      )}


      {/* --- MAIN LAYOUT --- */}
      <div className={`relative flex w-full max-w-7xl h-[85vh] transition-all duration-500 z-10 ${isWidgetMode ? 'h-screen max-w-none' : ''}`}>

        {/* Sidebar Dock */}
        {!isWidgetMode && (
          <div className={`
             absolute left-0 top-0 bottom-0 z-20 w-80 m-4 rounded-3xl backdrop-blur-xl border shadow-2xl flex flex-col overflow-hidden transition-all duration-300
             ${isDark ? 'bg-slate-900/80 border-white/10 text-white' : 'bg-white/80 border-white/50 text-slate-800'}
          `}>
            {/* Header */}
            <div className="p-6 pb-4 border-b border-white/5 flex items-center justify-between">
              <div>
                <h1 className="text-xl font-bold tracking-tight">ChronoVerse</h1>
                <p className="text-[10px] opacity-60 uppercase tracking-widest">Premium Clock Engine</p>
              </div>
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="p-2 hover:bg-white/10 rounded-full transition-colors"
                title="Settings"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              </button>
            </div>

            {/* Navigation Tabs */}
            <div className="flex p-2 gap-2 bg-black/5 mx-4 mt-4 rounded-xl">
              <button 
                onClick={() => setActiveTab('themes')}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wider rounded-lg transition-all ${activeTab === 'themes' ? (isDark ? 'bg-white text-black shadow-sm' : 'bg-black text-white shadow-sm') : 'opacity-50 hover:opacity-100'}`}
              >
                Faces
              </button>
              <button 
                onClick={() => setActiveTab('alarms')}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wider rounded-lg transition-all ${activeTab === 'alarms' ? (isDark ? 'bg-white text-black shadow-sm' : 'bg-black text-white shadow-sm') : 'opacity-50 hover:opacity-100'}`}
              >
                Alarms
              </button>
            </div>

            {/* Content Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">

              {activeTab === 'themes' && (
                <div className="space-y-6">
                  {(Object.keys(themesByCategory) as ThemeCategory[]).map(category => (
                    <div key={category}>
                      <h3 className="text-[10px] font-bold opacity-40 uppercase mb-2 ml-1 tracking-widest">{category}</h3>
                      <div className="grid grid-cols-1 gap-2">
                        {themesByCategory[category].map(theme => (
                          <button
                            key={theme.id}
                            onClick={() => setCurrentThemeId(theme.id)}
                            className={`w-full text-left p-3 rounded-xl transition-all duration-200 flex items-center space-x-3 border group
                              ${currentThemeId === theme.id 
                                ? 'bg-blue-600 border-blue-500 shadow-lg shadow-blue-500/20 text-white' 
                                : `border-transparent hover:scale-[1.02] ${isDark ? 'bg-white/5 hover:bg-white/10' : 'bg-white/40 hover:bg-white/60'}`}
                            `}
                          >
                             <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold ${currentThemeId === theme.id ? 'bg-white/20' : 'bg-black/10'}`}>
                               {theme.name.substring(0,1)}
                             </div>
                             <div>
                               <span className="block font-bold text-sm">{theme.name}</span>
                             </div>
                          </button>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {activeTab === 'alarms' && (
                <AlarmManager 
                  alarms={alarms} 
                  onAdd={addAlarm} 
                  onRemove={removeAlarm} 
                  onToggle={toggleAlarm}
                  isDarkMode={isDark}
                />
              )}
            </div>

            {/* Footer Controls */}
            <div className="p-4 border-t border-white/5 space-y-3 bg-black/5">
               {quote && (
                  <div className={`p-3 rounded-xl text-xs border ${isDark ? 'bg-black/20 border-white/5' : 'bg-white/40 border-black/5'}`}>
                    <p className="italic opacity-80 leading-relaxed">"{quote.text}"</p>
                    <p className="text-[10px] opacity-50 mt-1 text-right">— {quote.author}</p>
                  </div>
               )}

               <div className="grid grid-cols-2 gap-2">
                 <button 
                   onClick={toggleThemeMode}
                   className={`py-2 rounded-lg text-xs font-bold transition-colors border flex items-center justify-center gap-2
                     ${isDark ? 'bg-white/10 hover:bg-white/20 border-white/5' : 'bg-white/50 hover:bg-white/80 border-black/5'}
                   `}
                 >
                   {isDark ? 'Light' : 'Dark'}
                 </button>
                 <button 
                  onClick={toggleWidgetMode}
                  className={`py-2 rounded-lg text-xs font-bold transition-colors border flex items-center justify-center gap-2
                    ${isDark ? 'bg-white/10 hover:bg-white/20 border-white/5' : 'bg-white/50 hover:bg-white/80 border-black/5'}
                  `}
                 >
                   Widget Mode
                 </button>
               </div>
            </div>
          </div>
        )}

        {/* Main Clock Stage */}
        <div className={`
            flex-1 relative flex items-center justify-center transition-all duration-700 ease-in-out
            ${!isWidgetMode ? 'ml-0 lg:ml-[340px]' : ''}
        `}>
          {/* Main clock scaler and container */}
          <div 
             className={`transition-all duration-500
               ${isWidgetMode ? 'w-full h-full flex items-center justify-center' : (currentTheme.type === 'table' ? 'w-full h-full flex items-center justify-center' : 'w-full max-w-4xl aspect-video shadow-2xl rounded-3xl overflow-hidden bg-black/20 backdrop-blur-sm')}
               ${!isWidgetMode && currentTheme.type !== 'table' ? currentStyles.containerClass : ''}
             `}
             style={{ 
               transform: `scale(${isWidgetMode && settings.enableWidgetOverrides ? settings.widgetScale : settings.scale})` 
             }}
           >
             {renderClockFace()}
           </div>
        </div>
      </div>
    </div>
  );
};

const ControlBtn = ({ onClick, icon, label, active }: { onClick: () => void, icon: React.ReactNode, label: string, active?: boolean }) => (
  <button 
    onClick={onClick}
    className={`p-2 rounded-full transition-colors group relative ${active ? 'bg-blue-600 shadow-lg shadow-blue-600/50 hover:bg-blue-500' : 'hover:bg-white/20'}`}
  >
    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
      {icon}
    </svg>
    <span className="absolute -top-8 left-1/2 -translate-x-1/2 bg-black px-2 py-1 rounded text-[10px] opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none z-50">
      {label}
    </span>
  </button>
)

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { useTime } from './hooks/useTime';
import { useAlarms } from './hooks/useAlarms';
import { THEMES } from './constants';
import { QuoteData, ClockSettings, ThemeCategory } from './types';
import { AppleClock, MicrosoftClock, JapanClock, IndiaClock, ChinaClock, FlipClock, NixieClock, SwissClock, WordClock, BinaryClock, WashiClock, JaliClock, GalaxyClock, NasaClock } from './components/ClockThemes';
import { AlarmManager } from './components/AlarmManager';
import { SettingsMenu } from './components/SettingsMenu';
import { getCulturalQuote } from './services/geminiService';

const App: React.FC = () => {
  const time = useTime();
  const [currentThemeId, setCurrentThemeId] = useState<string>('swiss');
  const [isWidgetMode, setIsWidgetMode] = useState<boolean>(false);
  const [quote, setQuote] = useState<QuoteData | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'themes' | 'alarms'>('themes');
  const [showWidgetControls, setShowWidgetControls] = useState(false);

  // Shuffle State
  const [shuffleIntervalMs, setShuffleIntervalMs] = useState<number | null>(null); // null means OFF
  const [showShuffleMenu, setShowShuffleMenu] = useState(false);
  const [customShuffleMinutes, setCustomShuffleMinutes] = useState<string>('30');

  const currentTheme = THEMES.find(t => t.id === currentThemeId) || THEMES[0];

  // Background Transition State
  const [activeBg, setActiveBg] = useState(currentTheme.backgroundImage);
  const [nextBg, setNextBg] = useState<string | null>(null);

  const [settings, setSettings] = useState<ClockSettings>({
    is24Hour: false,
    showSeconds: true,
    showDate: true,
    scale: 1,
    customColor: null,
    themeMode: 'dark',
    enableWidgetOverrides: false,
    widgetScale: 1.0,
    widgetColor: null,
    defaultSnoozeMinutes: 5,
  });

  const { alarms, addAlarm, removeAlarm, toggleAlarm, triggeredAlarm, dismissAlarm, snoozeAlarm } = useAlarms(time);
  const currentStyles = currentTheme.modes[settings.themeMode];

  // Group themes by category for sidebar
  const themesByCategory = THEMES.reduce((acc, theme) => {
    const cat = theme.category;
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(theme);
    return acc;
  }, {} as Record<ThemeCategory, typeof THEMES>);

  useEffect(() => {
    // Quote fetching
    const fetchQuote = async () => {
      if (currentTheme.type === 'cultural' || currentTheme.id === 'apple' || currentTheme.id === 'microsoft') {
        const data = await getCulturalQuote(currentThemeId);
        setQuote(data);
      } else {
        setQuote({ text: currentTheme.description, author: "ChronoVerse" });
      }
    };
    fetchQuote();

    // Handle Background Transition
    if (currentTheme.backgroundImage !== activeBg && currentTheme.backgroundImage !== nextBg) {
       setNextBg(currentTheme.backgroundImage);
       const timer = setTimeout(() => {
         setActiveBg(currentTheme.backgroundImage);
         setNextBg(null);
       }, 800); // Matches CSS duration
       return () => clearTimeout(timer);
    }
  }, [currentThemeId, currentTheme.backgroundImage]); // eslint-disable-line

  // Shuffle Logic
  const navigateTheme = useCallback((direction: 'next' | 'prev') => {
    const currentIndex = THEMES.findIndex(t => t.id === currentThemeId);
    let newIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (newIndex >= THEMES.length) newIndex = 0;
    if (newIndex < 0) newIndex = THEMES.length - 1;
    setCurrentThemeId(THEMES[newIndex].id);
  }, [currentThemeId]);

  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (shuffleIntervalMs) {
      interval = setInterval(() => {
        navigateTheme('next');
      }, shuffleIntervalMs);
    }
    return () => clearInterval(interval);
  }, [shuffleIntervalMs, navigateTheme]);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setIsSettingsOpen(false);
        if (isWidgetMode) setIsWidgetMode(false);
        setShowShuffleMenu(false);
      }
      if (!isWidgetMode && !isSettingsOpen) {
        if (e.key === '1') setActiveTab('themes');
        if (e.key === '2') setActiveTab('alarms');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isWidgetMode, isSettingsOpen]);

  const toggleWidgetMode = () => setIsWidgetMode(!isWidgetMode);
  const toggleThemeMode = () => setSettings(s => ({...s, themeMode: s.themeMode === 'light' ? 'dark' : 'light'}));

  const setShuffle = (minutes: number | null) => {
    if (minutes === null) {
      setShuffleIntervalMs(null);
    } else {
      setShuffleIntervalMs(minutes * 60 * 1000);
    }
    setShowShuffleMenu(false);
  };

  const renderClockFace = () => {
    // Calculate overrides
    const useOverride = isWidgetMode && settings.enableWidgetOverrides;
    const finalScale = useOverride ? settings.widgetScale : settings.scale;
    const finalColor = useOverride ? settings.widgetColor : settings.customColor;

    const props = { 
      time, 
      mode: settings.themeMode, 
      themeStyles: currentStyles, 
      settings,
      overrideScale: finalScale,
      overrideColor: finalColor,
      isWidgetMode // Pass this down to faces if needed
    };

    // Use compound key to force re-animation when theme OR mode changes
    const KeyedComponent = (Component: React.FC<any>) => <Component key={`${currentThemeId}-${settings.themeMode}`} {...props} />;

    switch (currentThemeId) {
      case 'swiss': return KeyedComponent(SwissClock);
      case 'flip': return KeyedComponent(FlipClock);
      case 'nixie': return KeyedComponent(NixieClock);
      case 'galaxy': return KeyedComponent(GalaxyClock);
      case 'word': return KeyedComponent(WordClock);
      case 'binary': return KeyedComponent(BinaryClock);
      case 'apple': return KeyedComponent(AppleClock);
      case 'microsoft': return KeyedComponent(MicrosoftClock);
      case 'nasa': return KeyedComponent(NasaClock);
      case 'japan': return KeyedComponent(JapanClock);
      case 'washi': return KeyedComponent(WashiClock);
      case 'india': return KeyedComponent(IndiaClock);
      case 'jali': return KeyedComponent(JaliClock);
      case 'china': return KeyedComponent(ChinaClock);
      default: return KeyedComponent(AppleClock);
    }
  };

  const isDark = settings.themeMode === 'dark';

  return (
    <div className={`min-h-screen w-full flex items-center justify-center bg-cover bg-center overflow-hidden relative transition-all duration-300 font-sans ${isWidgetMode ? 'p-0' : 'p-4'}`}
         onMouseEnter={() => isWidgetMode && setShowWidgetControls(true)}
         onMouseLeave={() => isWidgetMode && setShowWidgetControls(false)}
    >

      {/* Smooth Background System */}
      <div 
         className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000 ease-in-out z-0"
         style={{ backgroundImage: `url('${activeBg}')`, opacity: isWidgetMode ? 0 : 1 }}
      />
      {nextBg && (
        <div 
          className="absolute inset-0 bg-cover bg-center animate-in fade-in duration-1000 ease-in-out z-0"
          style={{ backgroundImage: `url('${nextBg}')`, opacity: isWidgetMode ? 0 : 1 }}
        />
      )}

      <div className={`absolute inset-0 transition-all duration-1000 z-0 ${isWidgetMode ? '' : (isDark ? 'bg-black/60 backdrop-blur-md' : 'bg-white/40 backdrop-blur-md')}`}></div>

      <SettingsMenu 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={settings} 
        onUpdate={setSettings}
        isDarkMode={isDark}
      />

      {/* Alarm Notification Overlay */}
      {triggeredAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-xl animate-in fade-in zoom-in duration-300">
           <div className={`p-8 rounded-3xl shadow-2xl flex flex-col items-center text-center max-w-sm w-full mx-4 border ${isDark ? 'bg-slate-900 border-white/10 text-white' : 'bg-white border-slate-200 text-slate-900'}`}>
              <div className="w-20 h-20 rounded-full bg-red-500/20 flex items-center justify-center mb-6 animate-pulse">
                <svg className="w-10 h-10 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
              </div>
              <h2 className="text-5xl font-light mb-2">{time.hours}:{String(time.minutes).padStart(2,'0')}</h2>
              <p className="text-xl opacity-70 mb-8 font-medium">{triggeredAlarm.label || "Time is up"}</p>

              <div className="flex gap-4 w-full">
                <button 
                  onClick={snoozeAlarm}
                  className="flex-1 py-4 bg-white/10 hover:bg-white/20 backdrop-blur border border-white/10 font-bold rounded-2xl transition-all"
                >
                  Snooze
                </button>
                <button 
                  onClick={dismissAlarm}
                  className="flex-1 py-4 bg-red-500 hover:bg-red-600 text-white font-bold rounded-2xl transition-all shadow-lg shadow-red-500/40"
                >
                  Dismiss
                </button>
              </div>
           </div>
        </div>
      )}

      {/* Widget Control Bar (Hover) */}
      {isWidgetMode && (
        <div 
          className={`fixed top-8 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center transition-all duration-300
            ${showWidgetControls || showShuffleMenu ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 pointer-events-none'}
          `}
        >
          <div className="flex items-center gap-1 px-3 py-2 rounded-full bg-black/60 backdrop-blur-xl border border-white/10 text-white shadow-2xl">
            <ControlBtn onClick={() => navigateTheme('prev')} icon={<path d="M15 19l-7-7 7-7" />} label="Prev" />
            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <ControlBtn onClick={() => navigateTheme('next')} icon={<path d="M9 5l7 7-7 7" />} label="Next" />
            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <div className="relative">
              <ControlBtn 
                onClick={() => setShowShuffleMenu(!showShuffleMenu)} 
                icon={shuffleIntervalMs !== null
                  ? <path d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" className="animate-spin" />
                  : <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                }
                label={shuffleIntervalMs ? "Shuffle On" : "Shuffle"}
                active={shuffleIntervalMs !== null}
              />
              {/* Shuffle Menu Popover */}
              {showShuffleMenu && (
                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-3 w-40 bg-slate-800 border border-white/10 rounded-xl shadow-xl p-2 flex flex-col gap-1 z-50 animate-in slide-in-from-top-2">
                  <div className="text-[10px] text-white/50 px-2 py-1 uppercase tracking-wider font-bold">Interval</div>
                  {[5, 10, 15].map(min => (
                    <button 
                      key={min} 
                      onClick={() => setShuffle(min)}
                      className={`text-left px-3 py-2 rounded-lg text-xs font-bold transition-colors ${shuffleIntervalMs === min * 60000 ? 'bg-blue-600 text-white' : 'text-white hover:bg-white/10'}`}
                    >
                      Every {min} min
                    </button>
                  ))}
                  <div className="h-px bg-white/10 my-1"></div>
                   <div className="flex items-center gap-2 px-2 pb-1">
                      <input 
                        type="number" 
                        min="1" 
                        max="60"
                        className="w-12 bg-black/20 text-white text-xs p-1 rounded border border-white/10 text-center"
                        value={customShuffleMinutes}
                        onChange={(e) => setCustomShuffleMinutes(e.target.value)}
                      />
                      <button 
                        onClick={() => setShuffle(parseInt(customShuffleMinutes) || 5)}
                        className="text-[10px] bg-white/10 hover:bg-white/20 px-2 py-1.5 rounded text-white"
                      >
                        Set
                      </button>
                   </div>
                   {shuffleIntervalMs !== null && (
                     <button onClick={() => setShuffle(null)} className="mt-1 text-xs text-red-400 hover:bg-red-500/10 py-2 rounded-lg font-bold">Stop Shuffle</button>
                   )}
                </div>
              )}
            </div>

            <div className="w-px h-4 bg-white/20 mx-1"></div>

            <ControlBtn 
              onClick={toggleThemeMode} 
              icon={isDark 
