                  </div>
               )}

               <div className="grid grid-cols-2 gap-3 relative z-10">
                 <button 
                   onClick={toggleThemeMode}
                   className={`py-2.5 rounded-xl text-xs font-bold transition-all border flex items-center justify-center gap-2 ${glassButtonClass}`}
                 >
                   {isDark ? 'Light' : 'Dark'}
                 </button>
                 <button 
                  onClick={toggleWidgetMode}
                  className={`py-2.5 rounded-xl text-xs font-bold transition-all border flex items-center justify-center gap-2 ${glassButtonClass}`}
                 >
                   Widget Mode
                 </button>
               </div>
            </div>
          </div>
        )}

        {/* Main Clock Stage - Free Floating Glass Effect */}
        <div className={`
            flex-1 relative flex items-center justify-center transition-all duration-700 ease-in-out
            ${!isWidgetMode && !isScreensaverActive ? 'ml-0 lg:ml-[340px]' : ''}
        `}>
           {/* Render Outgoing Theme (Cross-fade) */}
           {prevThemeId && renderThemeFace(prevThemeId, 1, true)}

           {/* Render Current Theme */}
           {renderThemeFace(currentThemeId, 1, false)}

           {/* Screensaver Hint */}
           {isScreensaverActive && (
             <div className="absolute bottom-10 left-1/2 -translate-x-1/2 text-white/40 text-xs tracking-[0.5em] font-light animate-pulse">
               PRESS ANY KEY
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

